+
+            if (childContext.getAccessibleIndexInParent() != i) {
+                throw new RuntimeException(
+                        "getAccessibleIndexInParent returned an incorrect " +
+                                "value for AccessibleAWTListChild " + i);
+            }
+
+            AccessibleStateSet childStateSet =
